added = 0
for k, legend in legends.items():
    ans = data[k]["answer"]
    if "Обозначения:" in ans:
        continue
    data[k]["answer"] = ans + f"\n\nОбозначения: {legend}"
    added += 1

with open(path, "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("Added legends to", added, "questions")
